/* ---- Typography System ---- */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=Fira+Code&display=swap');

:root {
  /* Modular scale (1.25 ratio) */
  --fs-xs: 0.8rem;
  --fs-sm: 0.9rem;
  --fs-base: 1rem;
  --fs-md: 1.25rem;
  --fs-lg: 1.563rem;
  --fs-xl: 1.953rem;
  --fs-2xl: 2.441rem;
  --fs-3xl: 3.052rem;

  --ff-sans: 'Inter', system-ui, -apple-system, sans-serif;
  --ff-mono: 'Fira Code', 'Cascadia Code', monospace;

  --lh-tight: 1.2;
  --lh-normal: 1.6;
  --lh-loose: 1.8;
}

body {
  font-family: var(--ff-sans);
  font-size: var(--fs-base);
  line-height: var(--lh-normal);
  -webkit-font-smoothing: antialiased;
}

h1 { font-size: var(--fs-3xl); line-height: var(--lh-tight); font-weight: 700; }
h2 { font-size: var(--fs-2xl); line-height: var(--lh-tight); font-weight: 700; }
h3 { font-size: var(--fs-xl);  line-height: var(--lh-tight); font-weight: 600; }
h4 { font-size: var(--fs-lg);  line-height: var(--lh-tight); font-weight: 600; }

code, pre { font-family: var(--ff-mono); font-size: var(--fs-sm); }

.text-gradient {
  background: linear-gradient(135deg, #3b82f6 0%, #8b5cf6 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

:root {
  /* Primary palette */
  --clr-primary-50: #eff6ff;
  --clr-primary-100: #dbeafe;
  --clr-primary-200: #bfdbfe;
  --clr-primary-400: #60a5fa;
  --clr-primary-500: #3b82f6;
  --clr-primary-600: #2563eb;
  --clr-primary-700: #1d4ed8;

  /* Neutrals */
  --clr-gray-50: #f8fafc;
  --clr-gray-100: #f1f5f9;
  --clr-gray-200: #e2e8f0;
  --clr-gray-400: #94a3b8;
  --clr-gray-500: #64748b;
  --clr-gray-700: #334155;
  --clr-gray-800: #1e293b;
  --clr-gray-900: #0f172a;

  /* Semantic */
  --clr-success: #22c55e;
  --clr-warning: #f59e0b;
  --clr-error: #ef4444;

  /* Surfaces */
  --surface-bg: #ffffff;
  --surface-card: #ffffff;
  --surface-elevated: #ffffff;
  --text-primary: var(--clr-gray-900);
  --text-secondary: var(--clr-gray-500);
  --border-color: var(--clr-gray-200);
}

[data-theme='dark'] {
  --surface-bg: var(--clr-gray-900);
  --surface-card: var(--clr-gray-800);
  --surface-elevated: var(--clr-gray-700);
  --text-primary: var(--clr-gray-50);
  --text-secondary: var(--clr-gray-400);
  --border-color: var(--clr-gray-700);
}

/* ---- Reset & Global ---- */
*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  font-family: var(--ff-sans);
  color: var(--text-primary);
  background: var(--surface-bg);
  transition: background-color 0.3s ease, color 0.3s ease;
}

/* ---- Navbar ---- */
#navbar {
  position: fixed; top: 0; width: 100%; z-index: 100;
  display: flex; justify-content: space-between; align-items: center;
  padding: 1rem 2rem;
  background: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border-color);
  transition: background 0.3s, border-color 0.3s;
}
[data-theme='dark'] #navbar { background: rgba(15, 23, 42, 0.85); }

.nav-logo {
  font-weight: 700; font-size: var(--fs-md);
  color: var(--clr-primary-500); text-decoration: none;
}
.nav-links {
  list-style: none; display: flex; gap: 2rem;
}
.nav-links a {
  text-decoration: none; color: var(--text-primary); font-weight: 500;
  padding-bottom: 4px; border-bottom: 2px solid transparent;
  transition: color 0.2s, border-color 0.2s;
}
.nav-links a:hover,
.nav-links a.active {
  color: var(--clr-primary-500);
  border-bottom-color: var(--clr-primary-500);
}

/* ---- Hero ---- */
#hero {
  min-height: 100vh;
  display: flex; flex-direction: column;
  align-items: center; justify-content: center;
  padding: 6rem 2rem 2rem;
  background: linear-gradient(135deg, var(--clr-primary-50) 0%, #dbeafe 50%, #ede9fe 100%);
  position: relative;
}
[data-theme='dark'] #hero {
  background: linear-gradient(135deg, #0f172a 0%, #1e1b4b 50%, #1e293b 100%);
}

.hero-content {
  display: flex; align-items: center; gap: 4rem;
  max-width: 1100px; width: 100%;
}
.hero-text { flex: 1; }
.hero-greeting {
  font-size: var(--fs-md); color: var(--text-secondary);
  margin-bottom: 0.5rem;
}
.hero-content h1 { font-size: clamp(2.5rem, 5vw, 4rem); margin-bottom: 0.5rem; }
.tagline {
  font-size: var(--fs-lg); color: var(--clr-primary-500);
  font-weight: 600; margin-bottom: 1rem;
}
.hero-description {
  font-size: var(--fs-md); color: var(--text-secondary);
  max-width: 500px; margin-bottom: 2rem; line-height: var(--lh-loose);
}
.hero-cta { display: flex; gap: 1rem; flex-wrap: wrap; }

.hero-image img {
  width: 320px; height: 320px;
  border-radius: 50%; object-fit: cover;
  border: 6px solid var(--clr-primary-200);
  box-shadow: 0 0 0 12px rgba(59, 130, 246, 0.1);
}

/* ---- Buttons ---- */
.btn {
  display: inline-block; padding: 0.875rem 1.75rem;
  border-radius: 10px; font-weight: 600;
  text-decoration: none; cursor: pointer;
  border: 2px solid transparent;
  font-size: var(--fs-base);
  transition: transform 0.2s, box-shadow 0.2s, background 0.2s;
}
.btn-primary {
  background: var(--clr-primary-500); color: #fff;
  border-color: var(--clr-primary-500);
}
.btn-primary:hover {
  background: var(--clr-primary-600);
  transform: translateY(-2px);
  box-shadow: 0 4px 16px rgba(59, 130, 246, 0.4);
}
.btn-outline {
  background: transparent; color: var(--clr-primary-500);
  border-color: var(--clr-primary-500);
}
.btn-outline:hover {
  background: var(--clr-primary-50);
  transform: translateY(-2px);
}

/* Scroll indicator */
.scroll-indicator {
  position: absolute; bottom: 2rem;
  animation: bounce 2s infinite;
  font-size: 1.5rem; color: var(--text-secondary);
}
@keyframes bounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(8px); }
}

/* ---- Section shared ---- */
section { padding: 6rem 2rem; }
section h2 {
  text-align: center; margin-bottom: 3rem;
  font-size: var(--fs-2xl);
}

/* ---- About ---- */
#about { max-width: 1100px; margin: 0 auto; }
.about-grid {
  display: grid; grid-template-columns: 1fr 1fr; gap: 4rem;
  align-items: start;
}
.about-text p {
  color: var(--text-secondary); line-height: var(--lh-loose);
  margin-bottom: 1rem; font-size: var(--fs-md);
}
.social-links { display: flex; gap: 1rem; margin-top: 1.5rem; }
.social-link {
  display: flex; align-items: center; justify-content: center;
  width: 44px; height: 44px; border-radius: 50%;
  background: var(--clr-gray-100); color: var(--text-primary);
  transition: background 0.2s, color 0.2s, transform 0.2s;
}
.social-link:hover {
  background: var(--clr-primary-500); color: #fff;
  transform: translateY(-2px);
}
[data-theme='dark'] .social-link { background: var(--clr-gray-700); }

/* ---- Timeline ---- */
.timeline { position: relative; padding-left: 2rem; }
.timeline::before {
  content: ''; position: absolute; left: 7px; top: 0; bottom: 0;
  width: 2px; background: var(--clr-primary-200);
}
.timeline-item {
  position: relative; margin-bottom: 2rem;
  padding-left: 1.5rem;
}
.timeline-dot {
  position: absolute; left: -2rem; top: 4px;
  width: 16px; height: 16px; border-radius: 50%;
  background: var(--clr-primary-500);
  border: 3px solid var(--surface-bg);
}
.timeline-date {
  font-size: var(--fs-sm); color: var(--clr-primary-500);
  font-weight: 600;
}
.timeline-content h4 { margin: 0.25rem 0; }
.timeline-content p { color: var(--text-secondary); font-size: var(--fs-sm); }

/* ---- Skills ---- */
#skills { background: var(--surface-card); }
.skills-container {
  display: grid; grid-template-columns: 1fr 1fr;
  gap: 3rem; max-width: 900px; margin: 0 auto;
}
.skill-category h3 {
  font-size: var(--fs-lg); margin-bottom: 1.5rem;
  color: var(--clr-primary-500);
}
.skill-bar {
  margin-bottom: 1.25rem;
}
.skill-bar::before {
  content: attr(data-skill);
  display: flex; justify-content: space-between;
  font-weight: 500; font-size: var(--fs-sm);
  margin-bottom: 0.5rem;
}
.skill-bar-track {
  width: 100%; height: 10px;
  background: var(--clr-gray-200); border-radius: 999px;
  overflow: hidden;
}
.skill-bar-fill {
  height: 100%; border-radius: 999px;
  background: linear-gradient(90deg, var(--clr-primary-500), var(--clr-primary-400));
  width: 0; /* animated by JS */
  transition: width 1s ease-out;
}

[data-theme='dark'] .skill-bar-track { background: var(--clr-gray-700); }

// ---- Skill Bars: Build DOM and Animate ----
document.querySelectorAll('.skill-bar').forEach((bar) => {
  const skill = bar.dataset.skill;
  const level = bar.dataset.level;

  // Build inner markup
  const label = document.createElement('div');
  label.className = 'skill-bar-label';
  label.innerHTML = `<span>${skill}</span><span>${level}%</span>`;
  label.style.cssText = 'display:flex;justify-content:space-between;font-weight:500;font-size:0.9rem;margin-bottom:0.4rem;';

  const track = document.createElement('div');
  track.className = 'skill-bar-track';

  const fill = document.createElement('div');
  fill.className = 'skill-bar-fill';
  track.appendChild(fill);

  bar.innerHTML = '';
  bar.appendChild(label);
  bar.appendChild(track);
});

// Animate skill bars when they scroll into view
const skillObserver = new IntersectionObserver(
  (entries) => {
    entries.forEach((entry) => {
      if (entry.isIntersecting) {
        const fill = entry.target.querySelector('.skill-bar-fill');
        if (fill) {
          fill.style.width = entry.target.dataset.level + '%';
        }
        skillObserver.unobserve(entry.target);
      }
    });
  },
  { threshold: 0.3 }
);

document.querySelectorAll('.skill-bar').forEach((bar) => skillObserver.observe(bar));

