// ---- Contact Form ----
const form = document.getElementById('contactForm');
const submitBtn = document.getElementById('submitBtn');
const formStatus = document.getElementById('formStatus');

function showError(input, message) {
  const group = input.closest('.form-group');
  group.classList.add('invalid');
  group.querySelector('.error-msg').textContent = message;
}

function clearError(input) {
  const group = input.closest('.form-group');
  group.classList.remove('invalid');
  group.querySelector('.error-msg').textContent = '';
}

function isValidEmail(email) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function validateForm() {
  let valid = true;
  const name = form.querySelector('#name');
  const email = form.querySelector('#email');
  const message = form.querySelector('#message');

  if (name.value.trim().length < 2) {
    showError(name, 'Name must be at least 2 characters.');
    valid = false;
  } else { clearError(name); }

  if (!isValidEmail(email.value)) {
    showError(email, 'Please enter a valid email address.');
    valid = false;
  } else { clearError(email); }

  if (message.value.trim().length < 10) {
    showError(message, 'Message must be at least 10 characters.');
    valid = false;
  } else { clearError(message); }

  return valid;
}

// Clear errors in real-time
form.querySelectorAll('input, textarea').forEach((el) => {
  el.addEventListener('input', () => clearError(el));
});

// Submit handler
form.addEventListener('submit', async (e) => {
  e.preventDefault();

  // Honeypot check
  if (form.querySelector('[name="_honey"]').value) return;

  if (!validateForm()) return;

  submitBtn.disabled = true;
  submitBtn.textContent = 'Sending...';

  try {
    const res = await fetch('https://formspree.io/f/YOUR_FORM_ID', {
      method: 'POST',
      body: new FormData(form),
      headers: { Accept: 'application/json' },
    });

    if (res.ok) {
      formStatus.textContent = 'Message sent! I will get back to you soon.';
      formStatus.className = 'form-status success';
      form.reset();
    } else {
      throw new Error('Server error');
    }
  } catch {
    formStatus.textContent = 'Something went wrong. Please try again or email me directly.';
    formStatus.className = 'form-status error';
  } finally {
    submitBtn.disabled = false;
    submitBtn.textContent = 'Send Message';
  }
});

// Initialize EmailJS with your public key
import emailjs from '@emailjs/browser';

emailjs.init('YOUR_PUBLIC_KEY');

async function sendWithEmailJS(formData) {
  const templateParams = {
    from_name: formData.get('name'),
    from_email: formData.get('email'),
    subject: formData.get('subject'),
    message: formData.get('message'),
  };

  try {
    await emailjs.send('YOUR_SERVICE_ID', 'YOUR_TEMPLATE_ID', templateParams);
    return { ok: true };
  } catch (error) {
    console.error('EmailJS error:', error);
    return { ok: false };
  }
}

import os
import resend
from flask import Blueprint, request, jsonify

contact_bp = Blueprint('contact', __name__)

resend.api_key = os.environ['RESEND_API_KEY']

@contact_bp.route('/api/contact', methods=['POST'])
def send_contact_email():
    data = request.get_json()
    name = data.get('name', '').strip()
    email = data.get('email', '').strip()
    message = data.get('message', '').strip()

    if not all([name, email, message]):
        return jsonify({'error': 'All fields required'}), 400

    try:
        resend.Emails.send({
            'from': 'Contact Form <noreply@janedoe.dev>',
            'to': ['jane@janedoe.dev'],
            'reply_to': email,
            'subject': f'New message from {name}',
            'text': f'From: {name} ({email})\n\n{message}',
        })
        return jsonify({'message': 'Email sent'})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

