/* ---- Responsive: Mobile First ---- */

/* Base (mobile) */
.hero-content { flex-direction: column-reverse; text-align: center; gap: 2rem; }
.hero-cta { justify-content: center; }
.hero-image img { width: 200px; height: 200px; }
.about-grid { grid-template-columns: 1fr; }
.skills-container { grid-template-columns: 1fr; }
.project-cards { grid-template-columns: 1fr; }
.nav-links { display: none; }

/* Tablet (768px+) */
@media (min-width: 768px) {
  .hero-content { flex-direction: row; text-align: left; gap: 3rem; }
  .hero-cta { justify-content: flex-start; }
  .hero-image img { width: 280px; height: 280px; }
  .about-grid { grid-template-columns: 1fr 1fr; }
  .skills-container { grid-template-columns: 1fr 1fr; }
  .project-cards { grid-template-columns: repeat(auto-fill, minmax(320px, 1fr)); }
